import ast
with open('/workspace/test/env_data/linear_ce.py') as f:
    src = f.read()
tree = ast.parse(src)

forbidden = {'cross_entropy', 'log_softmax', 'nll_loss'}
for node in ast.walk(tree):
    if isinstance(node, ast.Attribute) and node.attr in forbidden:
        print(f'Found forbidden: {node.attr} at line {node.lineno}')
    if isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name) and node.func.id in forbidden:
            print(f'Found forbidden call: {node.func.id}')
print('Check complete')
